protected SalesPackingSlipHeaderTmp initializeSalesPackingSlipHeader()
{
    SalesPackingSlipHeaderTmp salesPackingSlipHeaderTmpCreated = next initializeSalesPackingSlipHeader();

    FWFTextBlockReportTextInit::newParameters(salesPackingSlipHeaderTmpCreated, this.parmCustPackingSlipJour()).addTexts();

    return salesPackingSlipHeaderTmpCreated;
}

protected SalesPackingSlipDetailsTmp initializeSalesPackingSlipLine(SalesPackingSlipHeaderTmp _salesPackingSlipHeaderTmp, SalesPackingSlipDPPackingSlipLineQuerySelection _packingSlipLineSelection)
{
    SalesPackingSlipDetailsTmp salesPackingSlipDetailsTmpCreated = next initializeSalesPackingSlipLine(_salesPackingSlipHeaderTmp, _packingSlipLineSelection);

    FWFTextBlockReportTextInit::newParameters(salesPackingSlipDetailsTmpCreated, _packingSlipLineSelection.parmCustPackingSlipTrans()).addTexts();

    return salesPackingSlipDetailsTmpCreated;
}
